+    ) {
+        let config = RecoveryConfig {
+            initial_delay: std::time::Duration::from_millis(init_ms),
+            max_delay: std::time::Duration::from_millis(max_ms),
+            backoff_factor: backoff,
+            jitter_fraction: 0.0,
+            ..RecoveryConfig::default()
+        };
